 59	        'This action will delete resource from k8s but still the resource can be fetched from Tekton Results',
 60	      )}
 61	    </p>
 62	  );
 63	
 64	  const launchDeleteModal =
 65	    !isResourceLoadedFromTR(obj) && tektonResultsFlag(obj)
 66	      ? useDeleteModal(obj, undefined, message)
 67	      : useDeleteModal(obj);
 68	  const { name, namespace } = obj.metadata;
 69	  const canDeleteTaskRun = useAccessReview({
 70	    group: TaskRunModel.apiGroup,
 71	    resource: TaskRunModel.plural,
 72	    verb: 'delete',
 73	    name,
 74	    namespace,
 75	  });
 76	
 77	  const onToggle = () => {
 78	    setIsOpen(!isOpen);
 79	  };
 80	
 81	  const onSelect = () => {
 82	    setIsOpen(false);
