 99	          isVisible: true,
100	        }}
101	      >
102	        {t('Delete {{resourceKind}}', { resourceKind: TaskRunModel.kind })}
103	      </DropdownItem>
104	    ) : (
105	      <DropdownItem
106	        key={KEBAB_ACTION_DELETE_ID}
107	        component="button"
108	        onClick={launchDeleteModal}
109	        data-test-action={KEBAB_ACTION_DELETE_ID}
110	      >
111	        {t('Delete {{resourceKind}}', { resourceKind: TaskRunModel.kind })}
112	      </DropdownItem>
113	    ),
114	  ];
