128	          data-test={KEBAB_BUTTON_ID}
129	          icon={<EllipsisVIcon />}
130	        />
131	      )}
132	      isOpen={isOpen}
133	      isPlain={false}
134	      popperProps={{ placement: 'bottom-end' }}
135	    >
136	      <DropdownList>{dropdownItems}</DropdownList>
137	    </Dropdown>
138	  );
139	};
