141	const TaskRunsRow: React.FC<RowProps<TaskRunKind>> = ({
142	  activeColumnIDs,
143	  obj,
144	  index,
145	}) => {
146	  const { t } = useTranslation('plugin__pipelines-console-plugin');
147	  const {isResourceManagedByKueue} = useMultiClusterProxyService({ labels: obj?.metadata?.labels });
148	  return (
149	    <>
150	      <TableData activeColumnIDs={activeColumnIDs} id="name">
